import React from 'react';
import { User, Eye, Image as ImageIcon, ArrowRight } from 'lucide-react';

function ProjectCard({ project, onClick }) {
  return (
    <div 
      onClick={onClick}
      className="group relative bg-white/5 border border-white/10 rounded-[2rem] overflow-hidden cursor-pointer hover:-translate-y-2 hover:shadow-[0_20px_40px_-15px_rgba(99,102,241,0.4)] transition-all duration-300 backdrop-blur-md flex flex-col"
    >
      {/* 🖼️ Image Section */}
      <div className="h-48 bg-[#050505] relative overflow-hidden">
        {project.imageUrl ? (
          <img 
            src={project.imageUrl} 
            alt={project.title} 
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-gray-600 gap-2">
            <ImageIcon className="w-10 h-10 group-hover:scale-110 transition-transform duration-500" />
            <span className="text-[10px] font-bold uppercase tracking-widest">No Cover Image</span>
          </div>
        )}
        
        {/* 🏷️ Category Badge */}
        <div className="absolute top-4 left-4">
          <span className="bg-indigo-600/90 backdrop-blur-md text-white text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-full shadow-lg border border-white/20">
            {project.category || 'App'}
          </span>
        </div>
      </div>

      {/* 📝 Content Section */}
      <div className="p-6 flex-1 flex flex-col">
        <h3 className="text-xl font-bold text-white mb-2 group-hover:text-indigo-400 transition-colors line-clamp-1">
          {project.title}
        </h3>
        
        <p className="text-sm text-gray-400 mb-6 line-clamp-2 flex-1">
          {project.description}
        </p>

        {/* 👤 Footer / Meta Data */}
        <div className="flex items-center justify-between pt-4 border-t border-white/10 mt-auto">
          
          {/* Author */}
          <div className="flex items-center gap-2 text-xs text-gray-400">
            <div className="w-6 h-6 rounded-full bg-indigo-500/20 flex items-center justify-center border border-indigo-500/30 text-indigo-300">
              <User className="w-3 h-3" />
            </div>
            <span className="font-medium truncate max-w-[120px]">
              {project.author || project.authorName || 'Unknown'}
            </span>
          </div>
          
          {/* Views & Action Arrow */}
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-1.5 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
              <Eye className="w-3.5 h-3.5" /> {project.views || 0}
            </div>
            <div className="w-7 h-7 rounded-full bg-white/5 flex items-center justify-center text-gray-400 group-hover:bg-indigo-600 group-hover:text-white transition-colors border border-white/5">
              <ArrowRight className="w-3.5 h-3.5 group-hover:translate-x-0.5 transition-transform" />
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

export default ProjectCard;
